以下代码的输出是什么？

```go
func main() {
    for i := 0; i < 3; i++ {
        defer fmt.Print(i, " ")
    }
}
```

以下代码的输出是什么？

```go
func calc() int {
    x := 1
    defer func() { x = 10 }()
    x = 2
    return x
}
func main() {
    fmt.Println(calc())
}
```

以下代码中 recover() 能否成功捕获 panic？为什么？

```go
func main() {
    go func() {
        panic("oops")
    }()
    defer func() {
        if r := recover(); r != nil {
            fmt.Println("recovered:", r)
        }
    }()
    time.Sleep(time.Second)
}
```
